import React from 'react'
import './serviceCard.css'

const ServiceCard = ( {serviceName}) => {

    return (
        <div class="serviceCard">

            <div id="s1" class="serviceImg img"></div>
            <p class="serviceName">{serviceName}</p>

        </div>
    )
}

export default ServiceCard
